fn find_max<T: PartialOrd>(slice: &[T]) -> Option<&T> {
    if slice.is_empty() {
        return None;
    }
    let mut max = &slice[0];
    for item in &slice[1..] {
        if item > max {
            max = item;
        }
    }
    Some(max)
}

The PartialOrd trait bound is required because the > comparison operator is defined by this trait. Without it, the compiler cannot guarantee that type T supports comparison. At compile time, Rust monomorphizes: if the code calls find_max::<i32>() and find_max::<String>(), the compiler generates two separate functions with specialized machine code for each type.

import time
from functools import wraps

def retry(max_attempts=3, delay=1):
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            last_exception = None
            for attempt in range(max_attempts):
                try:
                    return func(*args, **kwargs)
                except Exception as e:
                    last_exception = e
                    if attempt < max_attempts - 1:
                        time.sleep(delay)
            raise last_exception
        return wrapper
    return decorator

Rust's three ownership rules: (1) Each value has exactly one owner at a time. (2) When the owner goes out of scope, the value is dropped (freed). (3) Ownership can be transferred (moved) or temporarily borrowed (& for read, &mut for write), but not duplicated for non-Copy types.

C code that compiles but has use-after-free:
char* str = malloc(10);
strcpy(str, "hello");
free(str);
printf("%s", str);  // use-after-free: undefined behavior

In Rust, the equivalent would be:
let s = String::from("hello");
drop(s);  // explicit free
println!("{}", s);  // COMPILER ERROR: value used after move

The compiler rejects this because after drop(s), ownership has been consumed and s cannot be used.

def tokenize(source):
    tokens = []
    i = 0
    while i < len(source):
        ch = source[i]
        if ch.isspace():
            i += 1
        elif ch.isdigit():
            start = i
            while i < len(source) and source[i].isdigit():
                i += 1
            tokens.append(('NUMBER', int(source[start:i])))
        elif ch in '+-*/':
            tokens.append(('OP', ch))
            i += 1
        elif ch == '(':
            tokens.append(('LPAREN', ch))
            i += 1
        elif ch == ')':
            tokens.append(('RPAREN', ch))
            i += 1
        else:
            raise ValueError(f'Unexpected character: {ch!r} at position {i}')
    return tokens

# Example: tokenize('2 + 3 * (4 - 1)')
# [('NUMBER', 2), ('OP', '+'), ('NUMBER', 3), ('OP', '*'),
#  ('LPAREN', '('), ('NUMBER', 4), ('OP', '-'), ('NUMBER', 1), ('RPAREN', ')')]
